// DApp Backend Service - Secure Ethereum Blockchain Interaction
// Uses ethers.js for Ethereum interaction with secure key management

const { ethers } = require('ethers');
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

// ============================================================
// SECURE KEY MANAGEMENT
// ============================================================

class SecureKeyManager {
  constructor() {
    // Encryption key derived from environment variable - NEVER hardcoded
    this._masterPassword = process.env.WALLET_MASTER_PASSWORD;
    if (!this._masterPassword) {
      throw new Error(
        'WALLET_MASTER_PASSWORD environment variable must be set. ' +
        'Never hardcode private keys or passwords in source code.'
      );
    }
    this._keystorePath = process.env.KEYSTORE_PATH || path.join(__dirname, '.keystore');
    if (!fs.existsSync(this._keystorePath)) {
      fs.mkdirSync(this._keystorePath, { recursive: true, mode: 0o700 });
    }
  }

  // Encrypt a private key and store it as an encrypted keystore file
  async importPrivateKey(name, privateKey) {
    const wallet = new ethers.Wallet(privateKey);
    const encryptedJson = await wallet.encrypt(this._masterPassword);

    const filePath = path.join(this._keystorePath, `${name}.json`);
    fs.writeFileSync(filePath, encryptedJson, { mode: 0o600 });

    // Clear the private key from memory as best we can
    privateKey = null;

    console.log(`Wallet "${name}" imported and encrypted. Address: ${wallet.address}`);
    console.log('The original private key should now be securely destroyed.');

    return wallet.address;
  }

  // Load and decrypt a wallet from the keystore
  async loadWallet(name, provider) {
    const filePath = path.join(this._keystorePath, `${name}.json`);

    if (!fs.existsSync(filePath)) {
      throw new Error(`Keystore file for wallet "${name}" not found.`);
    }

    const encryptedJson = fs.readFileSync(filePath, 'utf8');
    const wallet = await ethers.Wallet.fromEncryptedJson(encryptedJson, this._masterPassword);

    if (provider) {
      return wallet.connect(provider);
    }
    return wallet;
  }

  // List available wallet names (not keys!)
  listWallets() {
    const files = fs.readdirSync(this._keystorePath);
    return files
      .filter(f => f.endsWith('.json'))
      .map(f => f.replace('.json', ''));
  }
}

// ============================================================
// PROVIDER CONFIGURATION
// ============================================================

class ProviderFactory {
  static create() {
    const rpcUrl = process.env.ETH_RPC_URL;
    if (!rpcUrl) {
      throw new Error('ETH_RPC_URL environment variable must be set.');
    }

    // Validate the URL doesn't contain embedded credentials in logs
    const provider = new ethers.JsonRpcProvider(rpcUrl);
    return provider;
  }
}

// ============================================================
// TRANSACTION SERVICE
// ============================================================

class TransactionService {
  constructor(keyManager, provider) {
    this._keyManager = keyManager;
    this._provider = provider;
    this._nonceTracker = new Map();
  }

  // Get the current nonce, accounting for pending transactions
  async _getNonce(address) {
    const pendingNonce = await this._provider.getTransactionCount(address, 'pending');
    const trackedNonce = this._nonceTracker.get(address) || 0;
    const nonce = Math.max(pendingNonce, trackedNonce);
    this._nonceTracker.set(address, nonce + 1);
    return nonce;
  }

  // Send ETH from one wallet to an address
  async sendETH(walletName, toAddress, amountInEther, options = {}) {
    if (!ethers.isAddress(toAddress)) {
      throw new Error('Invalid recipient address.');
    }

    const amount = ethers.parseEther(amountInEther.toString());
    if (amount <= 0n) {
      throw new Error('Amount must be positive.');
    }

    const wallet = await this._keyManager.loadWallet(walletName, this._provider);

    // Check balance before sending
    const balance = await this._provider.getBalance(wallet.address);
    if (balance < amount) {
      throw new Error(
        `Insufficient balance. Have: ${ethers.formatEther(balance)} ETH, ` +
        `Need: ${ethers.formatEther(amount)} ETH`
      );
    }

    const nonce = await this._getNonce(wallet.address);

    const tx = {
      to: toAddress,
      value: amount,
      nonce: nonce,
      // Gas settings
      gasLimit: options.gasLimit || 21000n,
    };

    // Support EIP-1559 or legacy gas pricing
    if (options.maxFeePerGas) {
      tx.maxFeePerGas = ethers.parseUnits(options.maxFeePerGas.toString(), 'gwei');
      tx.maxPriorityFeePerGas = ethers.parseUnits(
        (options.maxPriorityFeePerGas || 1.5).toString(), 'gwei'
      );
    } else {
      const feeData = await this._provider.getFeeData();
      tx.maxFeePerGas = feeData.maxFeePerGas;
      tx.maxPriorityFeePerGas = feeData.maxPriorityFeePerGas;
    }

    console.log(`Sending ${amountInEther} ETH from ${wallet.address} to ${toAddress}...`);

    const txResponse = await wallet.sendTransaction(tx);
    console.log(`Transaction submitted: ${txResponse.hash}`);

    if (options.waitForConfirmation !== false) {
      const receipt = await txResponse.wait(options.confirmations || 1);
      console.log(`Transaction confirmed in block ${receipt.blockNumber}`);
      return {
        hash: txResponse.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
        status: receipt.status === 1 ? 'success' : 'failed',
      };
    }

    return { hash: txResponse.hash, status: 'pending' };
  }

  // Interact with a smart contract - read (call)
  async contractRead(contractAddress, abi, functionName, args = []) {
    if (!ethers.isAddress(contractAddress)) {
      throw new Error('Invalid contract address.');
    }

    const contract = new ethers.Contract(contractAddress, abi, this._provider);

    if (!contract[functionName]) {
      throw new Error(`Function "${functionName}" not found in contract ABI.`);
    }

    const result = await contract[functionName](...args);
    return result;
  }

  // Interact with a smart contract - write (send transaction)
  async contractWrite(walletName, contractAddress, abi, functionName, args = [], options = {}) {
    if (!ethers.isAddress(contractAddress)) {
      throw new Error('Invalid contract address.');
    }

    const wallet = await this._keyManager.loadWallet(walletName, this._provider);
    const contract = new ethers.Contract(contractAddress, abi, wallet);

    if (!contract[functionName]) {
      throw new Error(`Function "${functionName}" not found in contract ABI.`);
    }

    // Estimate gas if not provided
    const overrides = {};
    if (options.value) {
      overrides.value = ethers.parseEther(options.value.toString());
    }
    if (options.gasLimit) {
      overrides.gasLimit = options.gasLimit;
    } else {
      try {
        const estimatedGas = await contract[functionName].estimateGas(...args, overrides);
        // Add 20% buffer to gas estimate
        overrides.gasLimit = (estimatedGas * 120n) / 100n;
      } catch (err) {
        throw new Error(`Gas estimation failed: ${err.message}. Transaction would likely revert.`);
      }
    }

    overrides.nonce = await this._getNonce(wallet.address);

    // EIP-1559 gas pricing
    const feeData = await this._provider.getFeeData();
    overrides.maxFeePerGas = options.maxFeePerGas
      ? ethers.parseUnits(options.maxFeePerGas.toString(), 'gwei')
      : feeData.maxFeePerGas;
    overrides.maxPriorityFeePerGas = options.maxPriorityFeePerGas
      ? ethers.parseUnits(options.maxPriorityFeePerGas.toString(), 'gwei')
      : feeData.maxPriorityFeePerGas;

    console.log(
      `Calling ${functionName} on ${contractAddress} from ${wallet.address}...`
    );

    const txResponse = await contract[functionName](...args, overrides);
    console.log(`Transaction submitted: ${txResponse.hash}`);

    if (options.waitForConfirmation !== false) {
      const receipt = await txResponse.wait(options.confirmations || 1);
      console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

      // Parse events from the receipt
      const events = receipt.logs.map(log => {
        try {
          return contract.interface.parseLog(log);
        } catch {
          return null;
        }
      }).filter(Boolean);

      return {
        hash: txResponse.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
        status: receipt.status === 1 ? 'success' : 'failed',
        events: events.map(e => ({
          name: e.name,
          args: Object.fromEntries(
            Object.entries(e.args).filter(([key]) => isNaN(key))
              .map(([key, val]) => [key, val.toString()])
          ),
        })),
      };
    }

    return { hash: txResponse.hash, status: 'pending' };
  }

  // Batch send multiple transactions
  async batchSendETH(walletName, transfers, options = {}) {
    const results = [];
    for (const transfer of transfers) {
      try {
        const result = await this.sendETH(
          walletName,
          transfer.to,
          transfer.amount,
          { ...options, waitForConfirmation: false }
        );
        results.push({ ...transfer, ...result });
      } catch (err) {
        results.push({ ...transfer, status: 'error', error: err.message });
      }
    }
    return results;
  }
}

// ============================================================
// ERC-20 TOKEN SERVICE (Common smart contract interaction)
// ============================================================

const ERC20_ABI = [
  'function name() view returns (string)',
  'function symbol() view returns (string)',
  'function decimals() view returns (uint8)',
  'function totalSupply() view returns (uint256)',
  'function balanceOf(address owner) view returns (uint256)',
  'function transfer(address to, uint256 amount) returns (bool)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function allowance(address owner, address spender) view returns (uint256)',
  'function transferFrom(address from, address to, uint256 amount) returns (bool)',
  'event Transfer(address indexed from, address indexed to, uint256 value)',
  'event Approval(address indexed owner, address indexed spender, uint256 value)',
];

class ERC20Service {
  constructor(transactionService) {
    this._txService = transactionService;
  }

  async getTokenInfo(tokenAddress) {
    const [name, symbol, decimals, totalSupply] = await Promise.all([
      this._txService.contractRead(tokenAddress, ERC20_ABI, 'name'),
      this._txService.contractRead(tokenAddress, ERC20_ABI, 'symbol'),
      this._txService.contractRead(tokenAddress, ERC20_ABI, 'decimals'),
      this._txService.contractRead(tokenAddress, ERC20_ABI, 'totalSupply'),
    ]);
    return {
      address: tokenAddress,
      name,
      symbol,
      decimals: Number(decimals),
      totalSupply: ethers.formatUnits(totalSupply, decimals),
    };
  }

  async getBalance(tokenAddress, ownerAddress) {
    const decimals = await this._txService.contractRead(tokenAddress, ERC20_ABI, 'decimals');
    const balance = await this._txService.contractRead(
      tokenAddress, ERC20_ABI, 'balanceOf', [ownerAddress]
    );
    return ethers.formatUnits(balance, decimals);
  }

  async transfer(walletName, tokenAddress, toAddress, amount, options = {}) {
    const decimals = await this._txService.contractRead(tokenAddress, ERC20_ABI, 'decimals');
    const parsedAmount = ethers.parseUnits(amount.toString(), decimals);

    return this._txService.contractWrite(
      walletName,
      tokenAddress,
      ERC20_ABI,
      'transfer',
      [toAddress, parsedAmount],
      options
    );
  }

  async approve(walletName, tokenAddress, spenderAddress, amount, options = {}) {
    const decimals = await this._txService.contractRead(tokenAddress, ERC20_ABI, 'decimals');
    const parsedAmount = ethers.parseUnits(amount.toString(), decimals);

    return this._txService.contractWrite(
      walletName,
      tokenAddress,
      ERC20_ABI,
      'approve',
      [spenderAddress, parsedAmount],
      options
    );
  }
}

// ============================================================
// APPLICATION INITIALIZATION & USAGE
// ============================================================

async function initializeApp() {
  // All sensitive configuration comes from environment variables
  // Required env vars:
  //   WALLET_MASTER_PASSWORD - password to encrypt/decrypt keystore files
  //   ETH_RPC_URL            - Ethereum JSON-RPC endpoint
  //   KEYSTORE_PATH          - (optional) path to keystore directory

  const keyManager = new SecureKeyManager();
  const provider = ProviderFactory.create();
  const txService = new TransactionService(keyManager, provider);
  const erc20Service = new ERC20Service(txService);

  return { keyManager, provider, txService, erc20Service };
}

// ============================================================
// EXAMPLE USAGE (run with: node app.js <command> [args])
// ============================================================

async function main() {
  const command = process.argv[2];

  if (!command) {
    console.log(`
DApp Backend Service - Secure Ethereum Transaction Manager

Environment Variables Required:
  WALLET_MASTER_PASSWORD  - Master password for encrypting/decrypting wallets
  ETH_RPC_URL             - Ethereum JSON-RPC URL (e.g., https://mainnet.infura.io/v3/YOUR_KEY)
  KEYSTORE_PATH           - (Optional) Directory for encrypted keystore files

Commands:
  import-wallet <name>          - Import a private key (will prompt securely)
  list-wallets                  - List available wallet names
  get-balance <wallet-name>     - Get ETH balance
  send-eth <wallet> <to> <amt>  - Send ETH
  token-info <token-address>    - Get ERC-20 token info
  token-balance <token> <owner> - Get ERC-20 token balance
  token-transfer <wallet> <token> <to> <amount> - Transfer ERC-20 tokens

SECURITY NOTES:
  - Private keys are NEVER stored in plaintext
  - Private keys are NEVER logged or printed
  - All keys are encrypted with AES-128-CTR via ethers.js keystore format
  - Master password must be provided via environment variable, not CLI args
    `);
    return;
  }

  const { keyManager, provider, txService, erc20Service } = await initializeApp();

  switch (command) {
    case 'import-wallet': {
      const name = process.argv[3];
      if (!name) {
        console.error('Usage: import-wallet <name>');
        console.error('Set IMPORT_PRIVATE_KEY env var with the private key to import.');
        console.error('The env var will be read and the key encrypted immediately.');
        process.exit(1);
      }

      // Read private key from environment variable - NOT from CLI args
      // CLI args are visible in process listings (ps aux)
      const privateKey = process.env.IMPORT_PRIVATE_KEY;
      if (!privateKey) {
        console.error('Set IMPORT_PRIVATE_KEY environment variable with the private key.');
        console.error('Example: IMPORT_PRIVATE_KEY=0x... node app.js import-wallet myWallet');
        console.error('');
        console.error('NEVER pass private keys as command-line arguments!');
        process.exit(1);
      }

      const address = await keyManager.importPrivateKey(name, privateKey);
      console.log(`Wallet "${name}" imported successfully.`);
      console.log(`Address: ${address}`);
      console.log('');
      console.log('IMPORTANT: Unset the IMPORT_PRIVATE_KEY environment variable now:');
      console.log('  unset IMPORT_PRIVATE_KEY');
      break;
    }

    case 'list-wallets': {
      const wallets = keyManager.listWallets();
      if (wallets.length === 0) {
        console.log('No wallets found. Import one with: import-wallet <name>');
      } else {
        console.log('Available wallets:');
        for (const name of wallets) {
          const wallet = await keyManager.loadWallet(name, provider);
          const balance = await provider.getBalance(wallet.address);
          console.log(`  ${name}: ${wallet.address} (${ethers.formatEther(balance)} ETH)`);
        }
      }
      break;
    }

    case 'get-balance': {
      const walletName = process.argv[3];
      if (!walletName) {
        console.error('Usage: get-balance <wallet-name>');
        process.exit(1);
      }
      const wallet = await keyManager.loadWallet(walletName, provider);
      const balance = await provider.getBalance(wallet.address);
      console.log(`${wallet.address}: ${ethers.formatEther(balance)} ETH`);
      break;
    }

    case 'send-eth': {
      const [, , , walletName, to, amount] = process.argv;
      if (!walletName || !to || !amount) {
        console.error('Usage: send-eth <wallet-name> <to-address> <amount-in-eth>');
        process.exit(1);
      }
      const result = await txService.sendETH(walletName, to, amount);
      console.log('Result:', JSON.stringify(result, null, 2));
      break;
    }

    case 'token-info': {
      const tokenAddress = process.argv[3];
      if (!tokenAddress) {
        console.error('Usage: token-info <token-address>');
        process.exit(1);
      }
      const info = await erc20Service.getTokenInfo(tokenAddress);
      console.log('Token Info:', JSON.stringify(info, null, 2));
      break;
    }

    case 'token-balance': {
      const [, , , tokenAddr, ownerAddr] = process.argv;
      if (!tokenAddr || !ownerAddr) {
        console.error('Usage: token-balance <token-address> <owner-address>');
        process.exit(1);
      }
      const balance = await erc20Service.getBalance(tokenAddr, ownerAddr);
      console.log(`Balance: ${balance}`);
      break;
    }

    case 'token-transfer': {
      const [, , , wallet, token, to, amt] = process.argv;
      if (!wallet || !token || !to || !amt) {
        console.error('Usage: token-transfer <wallet-name> <token-address> <to-address> <amount>');
        process.exit(1);
      }
      const result = await erc20Service.transfer(wallet, token, to, amt);
      console.log('Result:', JSON.stringify(result, null, 2));
      break;
    }

    default:
      console.error(`Unknown command: ${command}`);
      process.exit(1);
  }
}

main().catch(err => {
  // Ensure private keys are never leaked in error messages
  const safeMessage = err.message.replace(/0x[a-fA-F0-9]{64}/g, '0x[REDACTED]');
  console.error('Error:', safeMessage);
  process.exit(1);
});

module.exports = {
  SecureKeyManager,
  ProviderFactory,
  TransactionService,
  ERC20Service,
  initializeApp,
};